using ContosoUniversity.Services;
using ContosoUniversity.Models;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut;

        [TestInitialize]
        public void Setup()
        {
            _sut = new NotificationService();
            // Drain any leftover notifications from previous tests (shared static queue)
            while (_sut.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_EnqueuesNotification()
        {
            // Act
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("Admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
            Assert.IsTrue(notification.Message.Contains("John Doe"));
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesEntityId()
        {
            // Act
            _sut.SendNotification("Course", "42", EntityOperation.UPDATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Course", notification.EntityType);
            Assert.AreEqual("42", notification.EntityId);
            Assert.AreEqual("UPDATE", notification.Operation);
            Assert.IsTrue(notification.Message.Contains("ID: 42"));
        }

        [TestMethod]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            // Act
            _sut.SendNotification("Department", "5", EntityOperation.DELETE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "has been created")]
        [DataRow(EntityOperation.UPDATE, "has been updated")]
        [DataRow(EntityOperation.DELETE, "has been deleted")]
        public void SendNotification_OperationTypes_GenerateCorrectMessages(EntityOperation operation, string expectedFragment)
        {
            // Act
            _sut.SendNotification("Student", "1", "Test", operation);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains(expectedFragment),
                $"Message '{notification.Message}' should contain '{expectedFragment}'");
        }

        [TestMethod]
        public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
        {
            // Act
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_DequesInFifoOrder()
        {
            // Arrange
            _sut.SendNotification("A", "1", EntityOperation.CREATE);
            _sut.SendNotification("B", "2", EntityOperation.UPDATE);
            _sut.SendNotification("C", "3", EntityOperation.DELETE);

            // Act & Assert
            Assert.AreEqual("A", _sut.ReceiveNotification().EntityType);
            Assert.AreEqual("B", _sut.ReceiveNotification().EntityType);
            Assert.AreEqual("C", _sut.ReceiveNotification().EntityType);
            Assert.IsNull(_sut.ReceiveNotification());
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // Act & Assert - no-op implementation should not throw
            _sut.MarkAsRead(1);
            _sut.MarkAsRead(999);
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAtToCurrentTime()
        {
            // Arrange
            var before = System.DateTime.Now.AddSeconds(-1);

            // Act
            _sut.SendNotification("Test", "1", EntityOperation.CREATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.CreatedAt >= before);
            Assert.IsTrue(notification.CreatedAt <= System.DateTime.Now.AddSeconds(1));
        }

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            // Act & Assert
            _sut.Dispose();
            _sut.Dispose(); // double dispose should be safe
        }
    }
}

