using System.Collections.Generic;
using System.Linq;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Helpers
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Create_ReturnsCorrectPageItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 50).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.AreEqual(10, result.Count);
            Assert.AreEqual(1, result[0]);
            Assert.AreEqual(10, result[9]);
        }

        [TestMethod]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 50).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 2, 10);

            // Assert
            Assert.AreEqual(10, result.Count);
            Assert.AreEqual(11, result[0]);
            Assert.AreEqual(20, result[9]);
        }

        [TestMethod]
        public void Create_LastPage_ReturnRemainingItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 3, 10);

            // Assert
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(21, result[0]);
        }

        [TestMethod]
        public void TotalPages_CalculatedCorrectly()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.AreEqual(3, result.TotalPages);
        }

        [TestMethod]
        [DataRow(1, 10, 50, false, true)]   // First page
        [DataRow(2, 10, 50, true, true)]    // Middle page
        [DataRow(5, 10, 50, true, false)]   // Last page
        [DataRow(1, 10, 5, false, false)]   // Single page
        public void HasPreviousPage_And_HasNextPage_CorrectValues(
            int pageIndex, int pageSize, int totalItems,
            bool expectedHasPrevious, bool expectedHasNext)
        {
            // Arrange
            var source = Enumerable.Range(1, totalItems).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex, pageSize);

            // Assert
            Assert.AreEqual(expectedHasPrevious, result.HasPreviousPage);
            Assert.AreEqual(expectedHasNext, result.HasNextPage);
        }

        [TestMethod]
        public void PageIndex_SetCorrectly()
        {
            // Arrange
            var source = Enumerable.Range(1, 50).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 3, 10);

            // Assert
            Assert.AreEqual(3, result.PageIndex);
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            // Arrange
            var source = Enumerable.Empty<int>().AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.AreEqual(0, result.Count);
            Assert.AreEqual(0, result.TotalPages);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }
    }
}

