using System;
using System.IO;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Moq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class CoursesControllerTests
    {
        private SchoolContext _context;
        private CoursesController _controller;
        private Mock<IWebHostEnvironment> _mockEnv;
        private Mock<ILogger<CoursesController>> _mockLogger;
        private string _tempDir;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.Create();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();
            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);

            SeedData();
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
            if (Directory.Exists(_tempDir))
                Directory.Delete(_tempDir, true);
        }

        private void SeedData()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 100000,
                StartDate = new DateTime(2020, 1, 1)
            };
            _context.Departments.Add(dept);
            _context.Courses.AddRange(
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 4041, Title = "Macroeconomics", Credits = 3, DepartmentID = 1 }
            );
            _context.SaveChanges();
        }

        // --- Index Tests ---

        [TestMethod]
        public void Index_ReturnsViewWithAllCourses()
        {
            // Act
            var result = _controller.Index() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as System.Collections.Generic.List<Course>;
            Assert.IsNotNull(model);
            Assert.AreEqual(3, model.Count);
        }

        // --- Details Tests ---

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Details(null);

            // Assert
            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            // Act
            var result = _controller.Details(1050) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Course;
            Assert.IsNotNull(model);
            Assert.AreEqual("Chemistry", model.Title);
        }

        // --- Create GET Tests ---

        [TestMethod]
        public void Create_Get_ReturnsViewWithNewCourse()
        {
            // Act
            var result = _controller.Create() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Model);
            Assert.IsInstanceOfType(result.Model, typeof(Course));
        }

        // --- Create POST Tests ---

        [TestMethod]
        public void Create_Post_ValidCourse_NoImage_RedirectsToIndex()
        {
            // Arrange
            var course = new Course { CourseID = 9999, Title = "New Course", Credits = 4, DepartmentID = 1 };

            // Act
            var result = _controller.Create(course, null);

            // Assert
            Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
            Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
            Assert.IsNotNull(_context.Courses.Find(9999));
        }

        [TestMethod]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            var course = new Course { CourseID = 8888, Title = "X", Credits = 4, DepartmentID = 1 };
            _controller.ModelState.AddModelError("Title", "Error");

            // Act
            var result = _controller.Create(course, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual(course, result.Model);
        }

        [TestMethod]
        public void Create_Post_ValidImageFile_UploadsAndRedirects()
        {
            // Arrange
            var course = new Course { CourseID = 7777, Title = "Art", Credits = 2, DepartmentID = 1 };
            var mockFile = CreateMockFile("test.png", "image/png", 1024);

            // Act
            var result = _controller.Create(course, mockFile.Object);

            // Assert
            Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
            var savedCourse = _context.Courses.Find(7777);
            Assert.IsNotNull(savedCourse);
            Assert.IsTrue(savedCourse.TeachingMaterialImagePath.Contains("/Uploads/TeachingMaterials/"));
        }

        [TestMethod]
        [DataRow("test.exe")]
        [DataRow("test.txt")]
        [DataRow("test.pdf")]
        public void Create_Post_InvalidFileExtension_ReturnsViewWithError(string filename)
        {
            // Arrange
            var course = new Course { CourseID = 6666, Title = "Test", Credits = 2, DepartmentID = 1 };
            var mockFile = CreateMockFile(filename, "application/octet-stream", 1024);

            // Act
            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [TestMethod]
        public void Create_Post_FileTooLarge_ReturnsViewWithError()
        {
            // Arrange
            var course = new Course { CourseID = 5555, Title = "Test", Credits = 2, DepartmentID = 1 };
            var mockFile = CreateMockFile("large.png", "image/png", 6 * 1024 * 1024); // 6MB

            // Act
            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        // --- Edit GET Tests ---

        [TestMethod]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Edit((int?)null, null);

            // Assert
            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Edit(9999, null);

            // Assert
            Assert.IsInstanceOfType(result, typeof(NotFoundResult));
        }

        [TestMethod]
        public void Edit_Get_ValidId_ReturnsViewWithCourse()
        {
            // Act
            var result = _controller.Edit(1050, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Course;
            Assert.AreEqual("Chemistry", model.Title);
        }

        // --- Edit POST Tests ---

        [TestMethod]
        public void Edit_Post_ValidCourse_NoImage_RedirectsToIndex()
        {
            // Arrange
            var course = _context.Courses.Find(1050);
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
            course.Title = "Updated Chemistry";

            // Act
            var result = _controller.Edit(course, null);

            // Assert
            Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
        }

        [TestMethod]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            var course = new Course { CourseID = 1050, Title = "X", Credits = 4, DepartmentID = 1 };
            _controller.ModelState.AddModelError("Title", "Error");

            // Act
            var result = _controller.Edit(course, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

        // --- Delete GET Tests ---

        [TestMethod]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Delete(null);

            // Assert
            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Delete_Get_ValidId_ReturnsViewWithCourse()
        {
            // Act
            var result = _controller.Delete(1050) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Course;
            Assert.AreEqual("Chemistry", model.Title);
        }

        // --- DeleteConfirmed Tests ---

        [TestMethod]
        public void DeleteConfirmed_ValidId_RemovesCourseAndRedirects()
        {
            // Arrange
            var initialCount = _context.Courses.Count();

            // Act
            var result = _controller.DeleteConfirmed(1050);

            // Assert
            Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
            Assert.AreEqual(initialCount - 1, _context.Courses.Count());
        }

        [TestMethod]
        public void DeleteConfirmed_CourseWithImage_DeletesImageFile()
        {
            // Arrange
            var uploadsDir = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsDir);
            var imagePath = Path.Combine(uploadsDir, "test_image.png");
            File.WriteAllText(imagePath, "fake image");

            var course = _context.Courses.Find(1050);
            course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.png";
            _context.SaveChanges();

            // Act
            _controller.DeleteConfirmed(1050);

            // Assert
            Assert.IsFalse(File.Exists(imagePath));
        }

        // --- Helper ---

        private static Mock<IFormFile> CreateMockFile(string fileName, string contentType, long length)
        {
            var mock = new Mock<IFormFile>();
            mock.Setup(f => f.FileName).Returns(fileName);
            mock.Setup(f => f.ContentType).Returns(contentType);
            mock.Setup(f => f.Length).Returns(length);
            mock.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s => { });
            return mock;
        }
    }
}

