            // Act
            var result = _controller.DeleteConfirmed(instructor.ID);

            // Assert
            Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
            Assert.AreEqual(initialCount - 1, _context.Instructors.Count());
        }

        [TestMethod]
        public void DeleteConfirmed_InstructorIsDepartmentAdmin_ClearsAdminRelation()
        {
            // Arrange
            var instructor = _context.Instructors.First();
            var dept = _context.Departments.First();
