namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class NotificationsControllerTests
    {
        private SchoolContext _context;
        private NotificationsController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.Create();
            _controller = new NotificationsController(_context);
            // Drain the static notification queue before each test
            var svc = new NotificationService();
            while (svc.ReceiveNotification() != null) { }
            svc.Dispose();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        [TestMethod]
        public void GetNotifications_WhenNoNotifications_ReturnsEmptyList()
        {
            // Act
            var result = _controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            var jsonResult = result as JsonResult;
            Assert.IsNotNull(jsonResult);
        }

        [TestMethod]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Arrange - send some notifications via the shared queue
            var svc = new NotificationService();
            svc.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);
            svc.SendNotification("Course", "2", "Test Course", EntityOperation.UPDATE);
            svc.Dispose();

            // Act
            var result = _controller.GetNotifications() as JsonResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Value);
        }

        [TestMethod]
        public void MarkAsRead_ReturnsSuccessJson()
        {
            // Act
            var result = _controller.MarkAsRead(1) as JsonResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Value);
        }

        [TestMethod]
        public void Index_ReturnsView()
        {
            // Act
            var result = _controller.Index() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }
    }
}

