using ContosoUniversity.Models;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class ModelTests
    {
        [TestMethod]
        [DataRow("Doe", "John", "Doe, John")]
        [DataRow("Smith", "Jane", "Smith, Jane")]
        [DataRow("O'Brien", "Conan", "O'Brien, Conan")]
        public void Person_FullName_CombinesLastAndFirstName(string lastName, string firstName, string expected)
        {
            // Arrange
            var student = new Student
            {
                LastName = lastName,
                FirstMidName = firstName,
                EnrollmentDate = System.DateTime.Now
            };

            // Act & Assert
            Assert.AreEqual(expected, student.FullName);
        }

        [TestMethod]
        public void Instructor_FullName_CombinesLastAndFirstName()
        {
            // Arrange
            var instructor = new Instructor
            {
                LastName = "Fakhouri",
                FirstMidName = "Fadi",
                HireDate = System.DateTime.Now
            };

            // Act & Assert
            Assert.AreEqual("Fakhouri, Fadi", instructor.FullName);
        }

        [TestMethod]
        [DataRow(Grade.A)]
        [DataRow(Grade.B)]
        [DataRow(Grade.C)]
        [DataRow(Grade.D)]
        [DataRow(Grade.F)]
        public void Enrollment_Grade_AcceptsAllValues(Grade grade)
        {
            // Arrange
            var enrollment = new Enrollment { Grade = grade };

            // Assert
            Assert.AreEqual(grade, enrollment.Grade);
        }

        [TestMethod]
        public void Enrollment_Grade_CanBeNull()
        {
            // Arrange
            var enrollment = new Enrollment { Grade = null };

            // Assert
            Assert.IsNull(enrollment.Grade);
        }

        [TestMethod]
        public void Course_Properties_SetCorrectly()
        {
            // Arrange & Act
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/images/chem.png"
            };

            // Assert
            Assert.AreEqual(1050, course.CourseID);
            Assert.AreEqual("Chemistry", course.Title);
            Assert.AreEqual(3, course.Credits);
            Assert.AreEqual(1, course.DepartmentID);
            Assert.AreEqual("/images/chem.png", course.TeachingMaterialImagePath);
        }

        [TestMethod]
        public void Department_Properties_SetCorrectly()
        {
            // Arrange & Act
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000.00m,
                StartDate = new System.DateTime(2020, 1, 1),
                InstructorID = 5
            };

            // Assert
            Assert.AreEqual(1, dept.DepartmentID);
            Assert.AreEqual("Engineering", dept.Name);
            Assert.AreEqual(350000.00m, dept.Budget);
            Assert.AreEqual(5, dept.InstructorID);
        }

        [TestMethod]
        public void Notification_Properties_SetCorrectly()
        {
            // Arrange & Act
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "New student created",
                CreatedAt = new System.DateTime(2023, 1, 1),
                CreatedBy = "Admin",
                IsRead = false,
                ReadAt = null
            };

            // Assert
            Assert.AreEqual(1, notification.Id);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("42", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("New student created", notification.Message);
            Assert.AreEqual("Admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
            Assert.IsNull(notification.ReadAt);
        }

        [TestMethod]
        public void OfficeAssignment_Properties_SetCorrectly()
        {
            // Arrange & Act
            var office = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Smith 17"
            };

            // Assert
            Assert.AreEqual(1, office.InstructorID);
            Assert.AreEqual("Smith 17", office.Location);
        }

        [TestMethod]
        public void CourseAssignment_Properties_SetCorrectly()
        {
            // Arrange & Act
            var assignment = new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 101
            };

            // Assert
            Assert.AreEqual(1, assignment.InstructorID);
            Assert.AreEqual(101, assignment.CourseID);
        }
    }
}

